INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Some users report a learning curve to configure pipelines and Salesbot flows effectively$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$What was Kommo previously called?$q$, $q$Kommo was known as amoCRM until it rebranded in October 2022; the product, team and pricing carried over unchanged.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Does Kommo have a free plan?$q$, $q$No, Kommo does not offer a permanent free plan, but every paid tier includes a 14-day free trial with full feature access and no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$How much does Kommo cost?$q$, $q$Kommo starts at $15 per user per month for the Base plan, rising to $25 for Advanced and $45 for Pro, with a custom-priced Enterprise tier, all billed on a minimum six-month cycle.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Does Kommo integrate with WhatsApp?$q$, $q$Yes, WhatsApp is one of Kommo's core native channels, integrated directly into the unified inbox alongside Instagram, Messenger, Telegram, email and web chat.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$What is Salesbot in Kommo?$q$, $q$Salesbot is Kommo's no-code chatbot builder that lets teams design automated conversation flows for lead qualification, follow-up and appointment booking.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Who is Kommo best suited for?$q$, $q$Kommo is best suited for small and mid-sized sales, marketing and support teams that do a large share of their selling over messaging apps like WhatsApp and Instagram.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Messenger-based sales pipelines$q$, $q$Teams that sell primarily over WhatsApp and Instagram use Kommo to manage conversations and pipeline stages in one place.$q$, $q$SMB sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Automated lead qualification$q$, $q$Marketing and sales teams use Salesbot to automatically qualify inbound leads and route them to reps.$q$, $q$Growth and demand-gen teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Field sales lead capture$q$, $q$Reps at trade shows and events use the mobile app's business-card scanner to instantly create CRM records.$q$, $q$Field sales representatives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Base$q$, $q$$15/user/month$q$, $q$Monthly (min. 6-month commitment)$q$, NULL, $q$["2,500 active leads per user","1 WhatsApp number and Instagram account","Unified inbox and sales pipeline","Basic AI reply/task suggestions","Up to 3 AI agents"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Advanced$q$, $q$$25/user/month$q$, $q$Monthly (min. 6-month commitment)$q$, NULL, $q$["5,000 active leads per user","3 WhatsApp numbers and Instagram accounts","Salesbot no-code automation","Broadcast messaging","Up to 3 AI agents"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Pro$q$, $q$$45/user/month$q$, $q$Monthly (min. 6-month commitment)$q$, NULL, $q$["10,000 active leads per user","Unlimited channels and WhatsApp numbers","Booking and scheduling tools","Full AI kit with up to 50 AI agents","Sales and marketing analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual/custom$q$, NULL, $q$["Enterprise-grade security and SSO","Dedicated account manager","Priority support","Custom data processing terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kommo, known for over a decade as amoCRM before its 2022 rebrand, is a customer relationship management platform built around the idea that most sales conversations now happen inside messaging apps rather than email. Instead of treating WhatsApp, Instagram and web chat as bolted-on channels, Kommo routes every conversation into a single unified inbox tied to the underlying deal and contact record, so a sales rep sees the full conversation history alongside pipeline status, tasks and notes in one place.$q$, $q$The product is organized around a visual, kanban-style sales pipeline that reps can customize to match their own sales process, combined with a no-code automation builder (Salesbot) for constructing chatbot-driven qualification and follow-up flows, and a newer AI Agent layer that can draft replies, summarize threads and handle parts of a conversation autonomously. This combination makes Kommo popular with teams that do a large share of their selling over chat apps rather than phone or email.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kommo's core feature set centers on its unified inbox, which merges WhatsApp, Instagram Direct, Facebook Messenger, Telegram, email and website chat into one thread per contact, eliminating the need to check multiple apps to manage a single lead. Around that inbox sits a drag-and-drop sales pipeline with customizable stages, deal cards, task automation and lead-scoring rules that let managers see exactly where every deal stands.$q$, $q$Salesbot, Kommo's no-code automation builder, lets non-technical users design branching chatbot flows for lead qualification, appointment booking and re-engagement campaigns without writing code. The newer AI Agent capability builds on top of this by generating reply suggestions, summarizing long conversations, and in higher-tier plans operating with a degree of autonomy across dozens of concurrent agents. Native mobile apps for iOS and Android include a business-card scanner for quickly digitizing leads captured at in-person events, and the platform integrates with a large marketplace of third-party apps, payment gateways and e-commerce tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kommo prices per user per month across four tiers with a minimum six-month billing commitment: Base at $15, Advanced at $25, Pro at $45, and a custom-quoted Enterprise tier. Each step up increases the active-lead cap per user (2,500 to 5,000 to 10,000), the number of connected WhatsApp/Instagram accounts, and the depth of automation and AI features available, with Salesbot and broadcast messaging unlocked starting at Advanced and the full AI agent kit and analytics suite reserved for Pro and Enterprise.$q$, $q$All plans come with a 14-day free trial that requires no credit card and gives full access to every feature, limited only by 10GB of trial media storage. There is no permanent free plan, so teams that want to keep using Kommo beyond the trial must commit to one of the paid tiers, generally billed six months at a time.$q$]::text[], 2);
