INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$What channels does Kommunicate support?$q$, $q$Kommunicate supports website chat, native mobile apps, WhatsApp, Telegram, Instagram and email through a single AI agent layer.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Does Kommunicate offer a free trial?$q$, $q$Yes, every plan includes a 30-day free trial that does not require a credit card.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$How much does Kommunicate cost?$q$, $q$Kommunicate starts at $40 per month for the Starter plan, with a Professional plan at $200 per month and a custom-priced Enterprise tier; annual billing saves roughly 20 percent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Can Kommunicate hand off from bot to human agent?$q$, $q$Yes, the platform is built around seamless handoff from the AI chatbot to a live agent within the same inbox, preserving conversation context.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Does Kommunicate integrate with Zendesk or Salesforce?$q$, $q$Yes, Zendesk and Freshdesk integrations are available on the Professional plan, while Salesforce, HubSpot and Zapier integrations are part of the Enterprise tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Who founded Kommunicate?$q$, $q$Kommunicate was founded in 2020 by Devashish Mamgain and Adarsh Kumar, who previously built the chat-infrastructure startup Applozic.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$AI-first support deflection$q$, $q$Support teams deploy the Kompose chatbot to automatically resolve common questions before they reach a human agent.$q$, $q$E-commerce and SaaS support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Omnichannel customer messaging$q$, $q$Businesses consolidate WhatsApp, Instagram, web and email support into one AI-agent-driven inbox.$q$, $q$Mid-market customer service teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Helpdesk augmentation$q$, $q$Teams already using Zendesk or Freshdesk layer Kommunicate's AI chat on top without replacing their ticketing system.$q$, $q$Existing helpdesk users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Starter$q$, $q$$40/month ($34/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["1 AI agent","1 team member","250 conversations/month (~10K messages)","Web, mobile, WhatsApp, Telegram, Instagram","3-month chat history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Professional$q$, $q$$200/month ($167/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["2 AI agents","3 team members","2,000 conversations/month (~80K messages)","Zendesk, Freshdesk and Google Analytics integration","AI summaries, auto-resolve, agent assist","1-year chat history"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Custom AI agents and seats","Salesforce, HubSpot, Zapier integrations","Dedicated account manager","SLA-backed support","SSO and identity management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kommunicate is a customer support platform that pairs an AI chatbot with live-agent handoff so businesses can automate routine questions while keeping a clear path to a human for anything the bot cannot handle. Founded in 2020 by Devashish Mamgain and Adarsh Kumar, a team with prior experience building chat infrastructure, the company is based in Bengaluru, India, and serves support teams that want AI automation layered onto channels they already use rather than a wholesale platform replacement.$q$, $q$The product runs on a single AI agent layer that is deployed consistently across a website widget, mobile apps, WhatsApp, Telegram, Instagram and email, so a business configures its bot's knowledge base and flows once and it behaves the same everywhere a customer might message in. When the bot cannot resolve a query, the conversation hands off to a live agent inside the same inbox with full context preserved.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Kommunicate is its AI chatbot builder (Kompose), which lets non-technical teams design conversation flows and connect a knowledge base for instant answers, alongside a human handoff system that routes unresolved conversations to live support staff without losing context. Rich messaging support covers images, videos and quick replies across every connected channel.$q$, $q$Higher-tier plans add AI-generated conversation summaries, an auto-resolve feature for closing simple tickets automatically, agent-assist suggestions for human reps, and proactive campaign messaging for outbound engagement. Integrations extend into existing helpdesk stacks, connecting with Zendesk, Freshdesk and Google Analytics on the Professional plan and Salesforce, HubSpot and Zapier on Enterprise, plus API and webhook access for custom workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ab9318-aa3a-43fc-9832-012d933cd2d2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kommunicate's pricing scales primarily along three axes: number of AI agents, number of team members, and monthly conversation volume. Starter costs $40 per month for one AI agent, one seat and 250 conversations; Professional costs $200 per month for two AI agents, three seats and 2,000 conversations plus deeper integrations and automation features; and Enterprise is custom-priced with unlimited scale, dedicated support and SSO.$q$, $q$Annual billing discounts every tier by roughly 20 percent, bringing Starter to $34 per month and Professional to $167 per month. All plans include a 30-day free trial with no credit card required, and additional conversations beyond a plan's included volume are billed per thousand at rates that improve on higher tiers.$q$]::text[], 2);
