INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Kong Gateway (open source)$q$, $q$Plugin-extensible API gateway handling routing, auth, rate limiting and load balancing for REST, gRPC, GraphQL, Kafka and WebSockets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Kong Konnect control plane$q$, $q$Hosted SaaS layer with a developer portal, centralized analytics and service catalog across all gateways.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$AI Gateway$q$, $q$Routes and governs LLM traffic with rate limiting, token quotas, prompt governance and semantic caching.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Kong Mesh$q$, $q$Service-mesh product built on Kuma for managing microservice-to-microservice traffic.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Kong Insomnia$q$, $q$Standalone API client and testing tool for designing, debugging and documenting API requests.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Role-based access control and SSO$q$, $q$Enterprise-grade access governance available on Konnect Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Large plugin ecosystem$q$, $q$Extensible plugin architecture covering authentication, security, transformation and observability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Developer portal$q$, $q$Publish and document APIs for internal or external developer consumption.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Open-source Kong Gateway is free, production-ready and widely adopted$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Unified platform for both traditional API traffic and AI/LLM traffic governance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Large plugin ecosystem covers most authentication, security and transformation needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$30-day free trial of Konnect gives full enterprise functionality before committing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Backed by significant funding and a mature enterprise support organization$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Konnect's per-gateway pricing can become expensive as API programs scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Plugin development and Lua-based customization require specialized expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Enterprise pricing is not publicly listed and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Feature set can be more complex to configure than lighter, purpose-built gateways$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Some advanced governance features are gated behind the Enterprise tier only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Is Kong Gateway free to use?$q$, $q$Yes, Kong Gateway's Community Edition is open source and free to self-host with no functional limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$What is Kong Konnect?$q$, $q$Kong Konnect is Kong's hosted SaaS control plane that adds a developer portal, centralized analytics, service catalog and AI Gateway on top of Kong Gateway.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Does Kong support AI and LLM traffic?$q$, $q$Yes, Kong's AI Gateway routes and governs calls to large language models, applying rate limiting, token quotas and prompt governance similar to how it manages conventional API traffic.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Who founded Kong?$q$, $q$Kong originated as Mashape, founded in 2009 in Milan by Augusto Marietti, Marco Palladino and Michele Zonca, and rebranded to Kong Inc. in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$How much does Kong Konnect cost?$q$, $q$Konnect offers a 30-day free trial, then a per-gateway-priced Plus tier and a custom-priced, annually billed Enterprise tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$What is Kong Insomnia?$q$, $q$Kong Insomnia is a separate API client and testing tool for designing and debugging API requests, priced independently from the gateway with free, Pro and Enterprise tiers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Enterprise API management$q$, $q$Platform teams use Kong Gateway and Konnect to manage authentication, rate limiting and analytics across hundreds of internal and external APIs.$q$, $q$Enterprise platform and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$AI traffic governance$q$, $q$Teams route LLM calls through Kong's AI Gateway to enforce token quotas, prompt governance and cost control.$q$, $q$AI/ML platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Microservices connectivity$q$, $q$Organizations use Kong Mesh alongside Kong Gateway to manage service-to-service traffic in Kubernetes environments.$q$, $q$Cloud infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Kong Gateway (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted API gateway","Routing, auth, rate limiting, load balancing","REST, gRPC, GraphQL, Kafka, WebSocket support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Konnect Free Trial$q$, $q$$0 for 30 days$q$, $q$30-day trial$q$, NULL, $q$["Full enterprise functionality","No gateway limits","30-day analytics retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Konnect Plus$q$, $q$Custom, billed per gateway monthly$q$, $q$Monthly$q$, NULL, $q$["Up to 5 serverless gateways","Up to 2 hybrid/dedicated cloud gateways","AI Gateway with 5 LLM models","1M monthly analytics requests","RBAC and email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$Konnect Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Unlimited gateways","Unlimited developer portals and published APIs","SSO and audit logs","Dedicated Customer Success Manager","Customizable support SLAs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kong began life in 2009 as Mashape, an API marketplace founded in Milan, Italy, by Augusto Marietti, Marco Palladino and Michele Zonca. The team open-sourced an internal API gateway named Kong in 2015, and as that gateway eclipsed the marketplace in importance, the company sold off the marketplace business and rebranded entirely to Kong Inc. in 2017, moving its headquarters to San Francisco.$q$, $q$Today Kong describes itself as an API and AI connectivity company. Its core open-source Kong Gateway handles routing, authentication and traffic management for APIs, while its Konnect SaaS platform layers on a developer portal, analytics, governance and, more recently, an AI Gateway for managing and securing traffic to large language models alongside conventional API traffic.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kong Gateway is a plugin-extensible, Nginx/OpenResty-based API gateway that supports REST, HTTP, gRPC, GraphQL, Kafka and WebSocket protocols, handling authentication, rate limiting, load balancing and request/response transformation. Its open-source Community Edition is free to self-host and forms the foundation of Kong's entire product line.$q$, $q$Kong Konnect adds a hosted control plane on top of the gateway: a developer portal for publishing API documentation, centralized analytics across all gateways, a service catalog, role-based access control, and an AI Gateway that applies rate limiting, token quotas and prompt governance to LLM traffic from providers like OpenAI and Anthropic. The company also offers Kong Mesh for service-mesh use cases and Kong Insomnia, a standalone API client for designing and testing API requests.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kong follows a freemium model: the open-source Kong Gateway is free to self-host with no functional limits, and Konnect offers a 30-day free trial with full enterprise functionality. Beyond the trial, Konnect Plus is billed per gateway and includes up to five serverless gateways, an AI Gateway supporting five LLM models, and one million monthly analytics requests, while Konnect Enterprise is custom-priced and billed annually with unlimited gateways, SSO and dedicated customer success support.$q$, $q$Kong Insomnia, the company's API client, is priced separately from the gateway products, with a free Essentials tier, a $12-per-user-per-month Pro tier, and a $45-per-user-per-month Enterprise tier that adds SSO/SCIM and Konnect integration.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('739a3d06-32a8-47ca-88cb-0b897c628ff9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
