INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Visual workflow builder$q$, $q$Drag-and-drop graphical editor for building multi-step automations without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$800+ app integrations$q$, $q$Pre-built connectors spanning CRM, email marketing, payments, storage and communication tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Rules-based branching logic$q$, $q$Conditional workflow paths that go beyond simple linear if-this-then-that automations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Scheduled automation$q$, $q$Time-based triggers for running workflows on a recurring schedule.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$API and webhook support$q$, $q$Extend automations into custom or in-house systems not covered by pre-built connectors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Agency sub-accounts$q$, $q$Manage separate automation workspaces for multiple clients from one login on the Agency plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Free-forever plan$q$, $q$100 tasks per month at no cost with access to core platform features.$q$, 6);
