INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Genuinely usable free-forever plan, unlike many competitors' time-limited trials$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Significantly cheaper than Zapier at comparable task volumes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Supports multi-step, rules-based branching workflows even on lower tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Agency plan with sub-accounts suits businesses managing automations for multiple clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$800+ pre-built app integrations cover most common business tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Smaller app directory and community than market leaders like Zapier or Make$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Task-based pricing can be harder to predict than flat-rate competitors for variable workloads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Company headquarters and team size are not clearly published, limiting enterprise buyer confidence$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Less brand recognition and third-party documentation than larger automation platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Advanced workflow debugging and observability tools are less mature than more established competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Is KonnectzIT free to use?$q$, $q$Yes, KonnectzIT offers a permanently free plan that includes up to 100 tasks per month with access to core platform functionality.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$How much does KonnectzIT cost?$q$, $q$Paid plans start at $15 per month for the Team plan (15,000 tasks) and go up to $50 per month for the Agency plan (50,000 tasks, 5 sub-accounts), with a 20 percent discount for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$How many apps does KonnectzIT integrate with?$q$, $q$KonnectzIT connects to more than 800 third-party applications across categories including CRM, email marketing, payments, storage and communication.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Does KonnectzIT support conditional logic in workflows?$q$, $q$Yes, the platform supports rules-based branching logic and scheduled triggers, not just simple one-step automations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Who is KonnectzIT for?$q$, $q$KonnectzIT is aimed at founders, small business owners, operations staff and agencies who need to automate workflows without engineering resources.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$How does KonnectzIT compare to Zapier?$q$, $q$KonnectzIT positions itself as a lower-cost alternative to Zapier, offering a usable free tier and cheaper paid tiers while still supporting multi-step, branching workflows.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Lead routing and CRM sync$q$, $q$Small businesses automatically sync new leads from forms and ad platforms into their CRM and email marketing tools.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Agency automation management$q$, $q$Marketing agencies use sub-accounts to build and manage separate automation workflows for each client.$q$, $q$Marketing and operations agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$E-commerce order workflows$q$, $q$Online sellers automate order notifications, inventory updates and customer follow-ups across connected apps.$q$, $q$E-commerce operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["100 tasks/month","Access to core platform functions","Visual workflow builder"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Team$q$, $q$$15/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["15,000 tasks/month","Unlimited workflows","Up to 2 team members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Pro$q$, $q$$19/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["Higher task allowance","Unlimited workflows","Suited for freelancers and small businesses"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$Agency$q$, $q$$50/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["50,000 tasks/month","5 sub-accounts","Unlimited workflows"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KonnectzIT is a no-code automation platform, founded in 2020, that lets businesses connect over 800 web applications and automate multi-step workflows through a visual, drag-and-drop builder rather than writing custom integration code. It is positioned as a more affordable alternative to established automation tools like Zapier while still supporting conditional, rules-based logic rather than only simple linear triggers.$q$, $q$The platform is aimed at founders, small business owners and operations teams who need to move data between CRMs, email marketing tools, payment systems and communication apps without engineering support, as well as agencies that manage automation for multiple clients through dedicated sub-accounts.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of KonnectzIT is a graphical workflow editor that lets users chain triggers and actions across connected apps into what the platform calls a 'konnect,' supporting rules-based conditional branching and scheduled, time-based triggers rather than only simple one-step automations. The connector library spans more than 800 applications across CRM, email marketing, payments, storage and communication categories.$q$, $q$For workflows that fall outside the pre-built connector library, KonnectzIT exposes API and webhook access so developers can extend automations into custom or in-house systems. Agency-focused customers get access to sub-accounts, letting them manage separate automation workspaces for multiple clients from a single login.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KonnectzIT prices around monthly task-execution volume rather than a flat per-integration fee. A permanently free plan includes 100 tasks per month with access to core functionality, while paid tiers scale from a $15-per-month Team plan (15,000 tasks, up to 2 members) through a $19-per-month Pro plan up to a $50-per-month Agency plan offering 50,000 tasks, five sub-accounts and unlimited workflows.$q$, $q$Annual billing brings a 20 percent discount across every paid tier. This task-based, tiered pricing model is designed to make KonnectzIT noticeably cheaper than Zapier at comparable automation volumes while still allowing multi-step, branching workflows even on lower-priced plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
