INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26b90793-47fc-44e2-b4ed-aaab363f429f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Client-side end-to-end encryption$q$, $q$All snapshots are encrypted on the user's device with user-controlled keys before upload; unencrypted backups are not supported.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Content-based deduplication$q$, $q$Identical file content is stored only once across a repository, even across multiple machines or users.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Compression and error correction$q$, $q$Reduces storage footprint and protects against silent data corruption in stored snapshots.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Multiple repository backends$q$, $q$Supports Amazon S3, Azure Blob Storage, Backblaze B2, Google Cloud Storage, WebDAV/SFTP and local/NAS storage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$CLI and GUI (KopiaUI)$q$, $q$Command-line interface for automation plus a native graphical desktop app for visual backup management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Cross-platform support$q$, $q$Runs natively on Windows, macOS and Linux.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Configurable snapshot policies$q$, $q$Set retention rules, scheduling and exclusion filters for automated recurring backups.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Shared repository deduplication$q$, $q$Multiple users or computers can share one repository, deduplicating shared files across them.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Completely free and open source with no license or subscription fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Strong end-to-end encryption enforced by design, not optional$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Both CLI and polished GUI available for different user preferences$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Wide range of supported storage backends including S3, B2, Azure and local NAS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Backed by ongoing engineering investment from Kasten by Veeam$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$No commercial support contract or SLA available directly from a vendor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Users must bring and pay for their own storage backend separately$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Smaller community and ecosystem than more established tools like Restic or Borg$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Advanced configuration (policies, repository tuning) has a learning curve for new users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$No built-in cloud storage of its own, requiring third-party backend setup$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Is Kopia free to use?$q$, $q$Yes, Kopia is completely free and open source with no license fees or paid tiers; users only pay for their chosen storage backend.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Does Kopia encrypt backups?$q$, $q$Yes, Kopia encrypts all data client-side with user-controlled keys before it leaves the device, and does not support creating unencrypted backups.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$What storage backends does Kopia support?$q$, $q$Kopia supports Amazon S3 and S3-compatible services, Azure Blob Storage, Backblaze B2, Google Cloud Storage, WebDAV/SFTP servers, and local or network-attached storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Does Kopia have a graphical interface?$q$, $q$Yes, Kopia includes both a command-line interface and a native graphical desktop app called KopiaUI, available on Windows, macOS and Linux.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Who maintains Kopia?$q$, $q$Kopia is led by Google engineer Jarek Kowalski and receives ongoing development support from Kasten by Veeam, which uses Kopia for Kubernetes backup workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Does Kopia support deduplication?$q$, $q$Yes, Kopia performs content-based deduplication so identical file content is stored only once across a repository, even when shared across multiple machines.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Personal and home server backups$q$, $q$Privacy-conscious individuals use Kopia to back up personal files to encrypted cloud or local storage.$q$, $q$Individuals and self-hosters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Kubernetes-native data protection$q$, $q$Platforms like Kasten by Veeam embed Kopia as backup infrastructure for Kubernetes workloads.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Small team shared backup repositories$q$, $q$Small teams share a single deduplicated repository across multiple machines to save on storage costs.$q$, $q$Small IT teams and sysadmins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CLI and GUI access","Client-side encryption","Deduplication and compression","All supported repository backends"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kopia is a free, open-source backup and restore tool created and led by Google engineer Jarek Kowalski, designed to create encrypted, deduplicated snapshots of files and directories and store them in a repository of the user's choosing. Because it is a community open-source project rather than a company, it has no pricing, funding or headquarters вЂ” the software itself is entirely free to use.$q$, $q$The project receives ongoing engineering support from Kasten by Veeam, the Kubernetes-native backup division Veeam acquired in 2020, which uses Kopia internally for Kubernetes backup workflows and contributes to its continued development. This gives Kopia a level of sustained corporate investment that is unusual among community-maintained open-source backup tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kopia's defining feature is that it never creates unencrypted backups: every snapshot is encrypted client-side with user-controlled keys before leaving the device, protecting both file contents and file/directory names. Alongside encryption, Kopia performs content-based deduplication so identical data is stored only once across a repository, plus compression and error correction to minimize storage costs and guard against corruption.$q$, $q$Repository backends include Amazon S3 and S3-compatible storage, Azure Blob Storage, Backblaze B2, Google Cloud Storage, WebDAV/SFTP-accessible servers, and local or network-attached storage. Kopia ships with both a command-line interface for automation and scripting and a graphical desktop app (KopiaUI) for visual configuration, snapshot review and restores, with native support on Windows, macOS and Linux.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kopia itself is completely free and open source, with no license fees, subscriptions or paid tiers of any kind. The only cost users incur is for whichever storage backend they choose to pair with Kopia, such as Amazon S3, Backblaze B2 or Azure Blob Storage fees, which are billed directly by those providers rather than by the Kopia project.$q$, $q$This makes Kopia's total cost of ownership entirely a function of the storage a user selects and how much data they back up, rather than any fee tied to the backup software itself, distinguishing it from commercial backup services that charge per-device or per-user subscription fees on top of storage costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('806a6c41-0dfb-4b12-9209-416dc798214d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
