INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Git and Docker deployment$q$, $q$Deploy apps directly from a Git repository or Docker image with no server management required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Autoscaling and scale-to-zero$q$, $q$Services automatically scale with traffic and scale to zero when idle, billed per second of actual usage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$GPU inference support$q$, $q$On-demand access to NVIDIA RTX 4000, A100, H100, H200 and B200 GPUs billed per second.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Global edge distribution$q$, $q$Deploy services across multiple global regions with built-in load balancing and TLS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Serverless Postgres database$q$, $q$Managed, autoscaling Postgres database product with a free tier and pay-as-you-go compute.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Per-second billing$q$, $q$All compute, including GPUs, is billed per second with no minimum commitment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Committed capacity discounts$q$, $q$Long-term capacity reservations can save up to 50% off on-demand pricing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Startup credits program$q$, $q$Early-stage startups can access up to $30,000 in platform credits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Genuinely free, non-expiring Hobby plan with a bundled Postgres database$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Per-second billing on GPUs makes AI inference workloads cost-efficient$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Simple git-push deployment model without Kubernetes overhead$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Access to high-end GPUs (H100, H200, B200) without long-term commitments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Now backed by Mistral AI's infrastructure investment following the 2026 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Free Hobby tier is explicitly not intended for production traffic$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Smaller regional footprint than hyperscalers like AWS, Azure or GCP$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Enterprise pricing is not published and requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Post-acquisition roadmap and independence from Mistral AI's priorities is still unfolding$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Smaller team size relative to larger PaaS competitors could affect support responsiveness at scale$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Does Koyeb have a free plan?$q$, $q$Yes, Koyeb's Hobby plan is free forever, includes one web service and a small Postgres database instance, requires no credit card, and never expires, though it is not intended for production traffic.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$How much does Koyeb cost?$q$, $q$Paid plans start at $29/month for Pro (with $10 compute credit), $299/month for Scale (with $100 compute credit and a 99.9% SLA), and custom Enterprise pricing starting around $1,000/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Does Koyeb support GPU workloads?$q$, $q$Yes, Koyeb offers on-demand NVIDIA GPUs including RTX 4000, A100, H100, H200 and B200, billed per second starting around $0.50/hour.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Who owns Koyeb?$q$, $q$Koyeb was acquired by Mistral AI in February 2026, its first acquisition, to accelerate Mistral's cloud infrastructure ambitions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Where is Koyeb based?$q$, $q$Koyeb is headquartered in Paris, France, and was founded in 2020 by three former Scaleway employees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$How does Koyeb billing work?$q$, $q$Koyeb bills per second of actual compute usage, including GPU instances, with services able to scale to zero when idle.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$AI inference deployment$q$, $q$AI teams deploy model inference endpoints on Koyeb's GPU instances with per-second billing and scale-to-zero.$q$, $q$AI/ML engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$API and backend hosting$q$, $q$Developers deploy production APIs and backend services directly from Git without managing infrastructure.$q$, $q$Backend developers and startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Hobby and side projects$q$, $q$Individual developers use the free Hobby plan to host small personal projects and prototypes.$q$, $q$Individual developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 free web service (512MB RAM, 0.1 vCPU)","Free small Postgres database instance","No credit card required","Not intended for production"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Pro$q$, $q$$29/month + compute$q$, $q$Monthly$q$, NULL, $q$["$10 of compute credit included","Up to 10 users, 100 services","NVMe volumes","Up to 5 concurrent builds","Email/chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Scale$q$, $q$$299/month + compute$q$, $q$Monthly$q$, NULL, $q$["$100 of compute credit included","Up to 50 users, 1,000 services","Additional AWS regions","Slack integration","99.9% uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$Enterprise$q$, $q$Custom, from ~$1,000/month + compute$q$, $q$Custom$q$, NULL, $q$["$500 of compute credit included","Unlimited users","Private dedicated locations","SSO/RBAC","99.99% uptime SLA","24/7 premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Koyeb is a serverless cloud platform founded in 2020 by three former Scaleway employees, Yann LГ©ger, Г‰douard Bonlieu and Bastien Chatelard, and headquartered in Paris, France. It lets developers deploy applications, APIs and AI inference workloads directly from Git or Docker without managing servers, with automatic scaling, global distribution and per-second billing.$q$, $q$In February 2026, Mistral AI acquired Koyeb as its first-ever acquisition, bringing the roughly 13-person team into Mistral's engineering organization to accelerate Mistral Compute, the AI lab's cloud infrastructure initiative, signaling Koyeb's evolution from an independent developer platform toward core AI infrastructure for one of Europe's leading AI labs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Koyeb's core platform deploys apps directly from a Git repository or Docker image and handles autoscaling, load balancing, TLS and global edge distribution automatically, with services able to scale to zero when idle and back up on demand, billed per second of actual usage. This makes it a git-push deployment experience without the operational burden of managing Kubernetes or raw VMs.$q$, $q$For AI and machine learning workloads, Koyeb offers on-demand NVIDIA GPU access spanning RTX 4000 SFF up through A100, H100, H200 and B200 configurations, all billed per second with no minimum commitment, alongside a managed serverless Postgres database product with autoscaling storage for applications that need a bundled data layer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32feccb0-a63d-4932-b0a2-8d2a9ed9dd66', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Koyeb offers a genuinely free Hobby plan (one web service plus a small Postgres instance, no credit card required, never expires) alongside three paid tiers: Pro at $29/month with $10 of compute credit, Scale at $299/month with $100 of compute credit and a 99.9% SLA, and a custom Enterprise plan starting around $1,000/month with $500 of compute credit, unlimited users and a 99.99% SLA.$q$, $q$GPU compute is billed separately and per second, ranging from about $0.50/hour for an RTX 4000 SFF up to $24/hour for an 8x H200 configuration, with committed-capacity discounts of up to 50% available for teams that reserve capacity long-term, and an early-stage startup program offering up to $30,000 in credits.$q$]::text[], 2);
