INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Declarative, no-plugin-code configuration$q$, $q$Configure routing, rate limiting and transformations through JSON files instead of writing custom plugin code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Stateless, high-performance architecture$q$, $q$Go-based stateless design built for high throughput and low latency API traffic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Request aggregation$q$, $q$Combine multiple backend API calls into a single client-facing response.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$AI Gateway$q$, $q$Secure, govern and route traffic to multiple LLM providers with token quotas and prompt guardrails, bundled in Enterprise.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$SSO and RBAC$q$, $q$Single sign-on, SAML and role-based access control available on the Enterprise edition.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$gRPC and WebSocket support$q$, $q$Enterprise edition adds protocol support beyond standard REST/HTTP.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Audit logging and security patches$q$, $q$Enterprise customers receive immediate security fixes and full audit trails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Stable, usage-independent pricing$q$, $q$Enterprise pricing is not tied to the number of APIs or traffic throughput.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Community Edition is fully free, open source and production-capable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Declarative configuration avoids the need for custom plugin development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Frequently benchmarked among the fastest available API gateways$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$AI Gateway features are bundled into Enterprise at no extra license cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Enterprise pricing is not linked to API count or traffic volume, unlike many competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Enterprise pricing is not publicly listed and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Smaller plugin/extension ecosystem than more established competitors like Kong$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Some advanced security and governance features are Enterprise-only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Declarative-only configuration can feel restrictive to teams wanting custom plugin logic$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Smaller company size than larger API management vendors may affect long-term support depth$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Is KrakenD free to use?$q$, $q$Yes, KrakenD Community Edition is free and open source under the Apache 2.0 license, covering core routing, rate limiting and transformation features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$What is included in KrakenD Enterprise?$q$, $q$KrakenD Enterprise adds SSO/SAML, RBAC, audit logging, gRPC/WebSocket support, an AI Gateway for LLM traffic, and SLA-backed support with immediate security patches.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Does KrakenD support AI and LLM traffic?$q$, $q$Yes, KrakenD Enterprise includes an AI Gateway module that routes and secures traffic to providers like OpenAI, Claude, Gemini and Mistral with token quotas and prompt governance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$How is KrakenD Enterprise priced?$q$, $q$KrakenD Enterprise pricing is custom and not tied to the number of APIs or traffic throughput; a free two-month trial is available before committing to a quote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Who created KrakenD?$q$, $q$KrakenD was created in 2016 by Albert Lombarte, Daniel Lopez and Daniel Ortiz, with the company formally incorporated in Barcelona, Spain in 2021.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$What is the Lura Project?$q$, $q$The Lura Project is the name given to KrakenD's open-source core after it was contributed to the Linux Foundation in 2021.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$High-throughput microservices gateway$q$, $q$Engineering teams use KrakenD in front of microservices to handle routing, rate limiting and aggregation at high performance.$q$, $q$Platform and backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$AI traffic governance$q$, $q$Teams route and secure calls to multiple LLM providers through KrakenD's Enterprise AI Gateway.$q$, $q$AI platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$API response aggregation$q$, $q$Teams use KrakenD to combine multiple backend calls into a single simplified API response for client apps.$q$, $q$Mobile and frontend backend teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Declarative routing and rate limiting","Request/response transformation","API aggregation","Apache 2.0 open source license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$Enterprise Edition$q$, $q$Custom pricing (free 2-month trial)$q$, $q$Custom$q$, NULL, $q$["AI Gateway with multi-LLM routing","SSO/SAML and RBAC","Audit logging","gRPC, WebSockets, API Keys, OpenAPI","SLA-backed support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KrakenD is an open-source API gateway written in Go, created in 2016 by engineers Albert Lombarte, Daniel Lopez and Daniel Ortiz and formally incorporated as a company in 2021, headquartered in Barcelona, Spain. It was built around a stateless, declarative configuration model designed to deliver high throughput and low latency for API traffic without requiring custom plugin code for routine gateway behaviors.$q$, $q$The open-source core, KrakenD Community Edition, was contributed to the Linux Foundation in 2021 and renamed the Lura Project, while the KrakenD company continues to develop and sell a commercial Enterprise Edition that adds security, governance and, more recently, AI Gateway functionality on top of the free core.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$KrakenD Community Edition covers the core functions of an API gateway: declarative, JSON-configured routing, rate limiting, request/response transformation and the ability to aggregate multiple backend API calls into a single response, all without requiring developers to write plugin code. The gateway is stateless by design, which contributes to its reputation for high performance in benchmarks against other gateways.$q$, $q$KrakenD Enterprise Edition adds SSO/SAML, role-based access control, audit logging, gRPC and WebSocket support, API key management, OpenAPI integration, and immediate security patches with SLA-backed support. Its AI Gateway module, bundled at no extra license cost, secures and governs traffic to LLM providers like OpenAI, Claude, Gemini and Mistral with token quotas, prompt validation, data masking and multi-LLM routing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KrakenD Community Edition is free and open source under the Apache 2.0 license, covering the full core gateway functionality with no cost or usage limits. KrakenD Enterprise Edition is custom-priced and not published publicly, but the company markets its Enterprise pricing model as stable and predictable, explicitly not tied to the number of APIs managed or the volume of traffic processed.$q$, $q$Prospective Enterprise customers can trial the full feature set, including the AI Gateway, security policies and SSO, free for two months before committing to a paid contract, after which pricing is negotiated directly with KrakenD's sales team based on deployment scale and support needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
