INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27e34a6d-64ed-4d82-bdf3-3bc216000871', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Lead and deal pipeline management$q$, $q$Track leads and manage sales opportunities through a configurable, visual deal pipeline.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Sales forecasting$q$, $q$Forecast sales performance based on pipeline and historical deal data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Campaign and email marketing$q$, $q$Manage marketing campaigns and customer segmentation directly from the CRM.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Product catalog and quoting$q$, $q$Built-in product catalog and quoting module for generating sales quotes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$VoIP and live chat$q$, $q$Omnichannel customer engagement tools for calling and live chat support.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$AI-powered automation$q$, $q$AI-driven lead scoring, ticket classification, intent prediction and chatbot support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Self-hosted, open-source deployment$q$, $q$Fully self-hostable on Laravel with complete control over data and infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Multi-tenant SaaS module$q$, $q$Optional paid module for agencies to run Krayin as a hosted, white-labeled CRM.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Core CRM is entirely free under the MIT License with no per-user fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Built on the modern, widely known Laravel and Vue.js stack for easy customization$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Includes product catalog and quoting features often missing from other free CRMs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Backed by Webkul, an established software company with a track record supporting Bagisto$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Full data ownership through self-hosting rather than a vendor-hosted SaaS instance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Self-hosting requires technical resources to deploy, secure and maintain the server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Premium extensions like WhatsApp and VoIP integration carry significant one-time costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Smaller plugin ecosystem than more established open-source CRMs like SuiteCRM$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$No official managed cloud-hosted version directly from Krayin for non-technical teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Newer project (launched 2021) with a smaller long-term track record than older competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Is Krayin CRM free?$q$, $q$Yes, the core Krayin CRM is free and open source under the MIT License, with no per-user licensing fees for self-hosted deployment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$What technology is Krayin CRM built on?$q$, $q$Krayin CRM is built on the Laravel PHP framework with a Vue.js frontend, the same stack used by Webkul's Bagisto e-commerce platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Who built Krayin CRM?$q$, $q$Krayin CRM was launched in 2021 by Jitendra Singh, Saurav Pathak and Vipin Sahu, and is developed by Webkul Software, headquartered in Noida, India.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Does Krayin CRM have premium add-ons?$q$, $q$Yes, Webkul sells optional one-time-purchase extensions such as WhatsApp integration ($1,499) and VoIP calling ($4,500) on top of the free core CRM.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Can Krayin CRM be self-hosted?$q$, $q$Yes, Krayin is designed to be fully self-hosted on a business's own servers or cloud provider rather than requiring a vendor-hosted SaaS subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Does Krayin CRM support AI features?$q$, $q$Yes, recent versions include AI-powered lead scoring, support-ticket classification, customer intent prediction and an AI chatbot.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Self-hosted sales pipeline management$q$, $q$SMEs deploy Krayin on their own infrastructure to manage leads and deals without per-user SaaS fees.$q$, $q$Small and medium-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Agency white-label CRM$q$, $q$Digital agencies use Krayin's multi-tenant SaaS module to offer a branded CRM product to their own clients.$q$, $q$Digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Custom CRM development$q$, $q$Laravel developers extend Krayin's open-source codebase to build a fully customized CRM for specific business needs.$q$, $q$PHP/Laravel developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Lead and deal pipeline management","Sales forecasting","Campaign and email marketing","Product catalog and quoting","MIT License, self-hosted"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$Premium Extensions$q$, $q$From $1,499 (one-time)$q$, $q$One-time purchase$q$, NULL, $q$["WhatsApp integration ($1,499)","VoIP integration ($4,500)","Sold individually via Webkul store"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Krayin CRM is a free, open-source customer relationship management platform launched in 2021 by Jitendra Singh, Saurav Pathak and Vipin Sahu, and built by Webkul Software, an Indian IT company headquartered in Noida that is also known for the open-source e-commerce platform Bagisto. Krayin applies the same open-source, self-hosted philosophy to the CRM category, built entirely on Laravel with a Vue.js frontend.$q$, $q$Because Krayin is self-hosted and released under the MIT License, businesses can deploy, modify and use it commercially without any per-user licensing fee, distinguishing it from subscription-based commercial CRMs like Salesforce or HubSpot while still covering the core functional areas those platforms are known for.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Krayin covers lead capture and tracking, a visual deal pipeline with configurable stages, sales forecasting, and campaign management tools for email marketing and customer segmentation. It also bundles a product catalog and quoting module for generating sales quotes directly from the CRM, functionality that many competing open-source and commercial CRMs reserve for paid tiers.$q$, $q$More recent releases have added AI-powered automation, including AI-driven lead scoring, automated support-ticket classification, customer intent prediction and an AI chatbot for handling routine inquiries, alongside existing omnichannel tools like VoIP calling, live chat and structured customer feedback collection.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Krayin CRM is entirely free and released under the MIT License, allowing businesses to self-host, modify and deploy it commercially without any licensing cost. Webkul monetizes the project instead through optional premium extensions sold as one-time purchases, such as a WhatsApp integration priced at $1,499 and a VoIP calling extension at $4,500.$q$, $q$Additional revenue comes from paid implementation, customization and support services for businesses that want professional help deploying Krayin, as well as a multi-tenant SaaS module that lets agencies run Krayin as a hosted, white-labeled CRM product for their own clients.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a346f9ff-ee8c-46ac-9a67-521ae858c58b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
